#!/usr/bin/env dotnet
#:include *.cs
#:include Models/*.cs
#:exclude Scratch.cs

var person = new Person("Ada", "Lovelace");
Console.WriteLine(NameHelper.ToUpperFullName(person));

static class NameHelper
{
    public static string ToUpperFullName(Person person)
        => $"{person.FirstName} {person.LastName}".ToUpperInvariant();
}

